using Nalix.Common.Diagnostics;
using Nalix.Framework.Configuration;
using Nalix.Graphics.Engine;
using Nalix.Logging.Extensions;

namespace AutoX.Gara.Launcher;

public static class Program
{
    [System.STAThread]
    [System.Diagnostics.CodeAnalysis.SuppressMessage("Roslynator", "RCS1163:Unused parameter", Justification = "<Pending>")]
    [System.Diagnostics.CodeAnalysis.SuppressMessage("Style", "IDE0060:Remove unused parameter", Justification = "<Pending>")]
    public static void Main(System.String[] args)
    {
        NLogixFx.MinimumLevel = LogLevel.Debug;
        ConfigurationManager.Instance.Get<GraphicsConfig>().Title = "AutoX Gara Launcher";
        ConfigurationManager.Instance.Get<GraphicsConfig>().ScreenWidth = 500;
        ConfigurationManager.Instance.Get<GraphicsConfig>().ScreenHeight = 620;

        GraphicsEngine.Instance.SetIcon(Gears);
        GraphicsEngine.Instance.Launch();
    }

    private const System.String Gears = "";
}
